    "component_interactions": [
      {
        "from": "KYC Verification Service",
        "to": "Onfido API",
        "status": "risk",
        "issue": "Synchronous blocking call with no circuit breaker or fallback. Onfido's SLA (99.9%) is strictly lower than the team's internal SLA target (99.95%), making it mathematically impossible to meet the internal SLA through this dependency alone. Every minute of Onfido downtime directly blocks user registration."
      },
      {
        "from": "User Registration Flow",
        "to": "KYC Verification Service",
        "status": "risk",
        "issue": "Registration is hard-gated on KYC completion. No async path or 'pending verification' state exists, so Onfido latency spikes or outages cascade directly into user-facing registration failures (503)."
      }
    ],
    "contract_compliance": "Onfido API contract appears followed, but the integration does not account for Onfido's documented SLA ceiling. The team's 99.95% target requires the KYC path to tolerate Onfido's 0.1% allowed downtime (~8.7 hours/year) without failing user registrations.",
    "data_flow_integrity": "Structured JSON logging and metrics (kyc_checks_total, kyc_duration_histogram) provide visibility into the happy path. However, there is no mention of persisting partial registration state, so a failed Onfido call loses all onboarding progress for that user."
  },

  "observability_review": {
    "logging": {
      "coverage": "adequate",
      "gaps": [
        "No mention of logging Onfido error response bodies or correlation IDs for support escalation to Onfido",
        "No structured log field for failure reason categorization (timeout vs 5xx vs 4xx vs network error)"
      ]
    },
    "metrics": {
      "coverage": "Baseline metrics exist (kyc_checks_total, kyc_duration_histogram) but are incomplete for production operations",
      "gaps": [
        "No error-rate metric broken down by failure type (timeout, 5xx, 4xx, network)",
        "No metric for Onfido circuit breaker state (since circuit breaker does not exist)",
        "No metric tracking registration-blocked-by-kyc duration from user perspective",
        "No SLI/SLO burn-rate alert to detect when the 99.95% target is being eroded"
      ]
    },
    "tracing": {
      "coverage": "Not mentioned",
      "gaps": [
        "No distributed tracing context propagated through the registration -> KYC -> Onfido call chain",
        "Cannot correlate a slow registration with the specific Onfido request that caused it"
      ]
    },
    "debugging_capability": "Moderate. An on-call engineer can see that KYC checks are failing via metrics and logs, but cannot easily distinguish between Onfido-side issues and network/infrastructure issues without error categorization. The /health endpoint checking Onfido reachability is good for basic liveness but does not help with intermittent degradation."
  },

  "resilience_assessment": {
    "failure_modes": [
      {
        "scenario": "Onfido full outage (within their 0.1% allowed downtime)",
        "handling": "unhandled",
        "recommendation": "MUST-HAVE: Implement a degraded mode. Options: (1) async KYC with a 'pending verification' user state that allows limited platform access, (2) queue-based retry with user notification, or (3) secondary KYC provider failover. Option 1 is the most pragmatic path to meeting the 99.95% SLA."
      },
      {
        "scenario": "Onfido latency spike (p99 approaching or exceeding 5s timeout)",
        "handling": "partial",
        "recommendation": "The 5s timeout prevents indefinite hangs but there is no circuit breaker to stop hammering a degraded Onfido. MUST-HAVE: Add a circuit breaker (e.g., 50% error rate over 30s window -> open circuit) to fail fast and protect both your service and Onfido from cascading load."
      },
      {
        "scenario": "Sustained Onfido 5xx errors (service up but returning errors)",
        "handling": "unhandled",
        "recommendation": "Add retry with exponential backoff (1 retry, jittered, max 2s) for 5xx responses only. Combined with circuit breaker, this handles transient errors without amplifying sustained failures."
      },
      {
        "scenario": "Thundering herd after Onfido recovery",
        "handling": "unhandled",
        "recommendation": "Without a circuit breaker half-open state or request queue, all backed-up registration attempts will slam Onfido simultaneously on recovery. Circuit breaker with gradual half-open probing addresses this."
      },
      {
        "scenario": "Onfido DNS resolution failure or TLS handshake timeout",
        "handling": "partial",
        "recommendation": "The 5s timeout likely covers this, but these should be logged as distinct failure categories for faster diagnosis."
      }
    ],
    "retry_config": "None configured. At minimum, a single retry with jitter for 5xx/timeout responses would improve reliability without significantly increasing Onfido load.",
    "timeout_config": "5s timeout is reasonable given Onfido's documented p99 of 3s. Provides ~2s headroom. Acceptable.",
    "circuit_breakers": "None. This is the single most critical gap. Without a circuit breaker, a degraded Onfido results in every registration attempt waiting 5s then failing, consuming server threads/connections and degrading overall service health.",
    "graceful_degradation": "None. The service has a binary mode: Onfido works or registration fails. This is the root cause of the SLA arithmetic problem."
  },

