    "deployment_ready": false,
    "rollback_capable": true,
    "rollback_plan": "Redeploy previous container image. Acceptable for a stateless service, though no mention of database migration safety or feature flag to disable KYC gating in an emergency.",
    "monitoring_coverage": "Partial. Basic metrics and health check exist but lack error categorization, SLO burn-rate alerting, and distributed tracing needed for production operation of a critical-path service.",
    "on_call_documentation": "Not mentioned. A runbook is needed covering: (1) what to do when Onfido is down, (2) how to identify Onfido vs internal failures, (3) emergency bypass procedures if they exist, (4) Onfido support escalation contacts and SLA claim process.",
    "new_infrastructure_required": {
      "new_env_vars": [],
      "new_services": [],
      "new_queues_topics": [
        "If async KYC fallback is implemented: a durable queue (e.g., SQS/RabbitMQ) for deferred KYC checks"
      ],
      "config_changes": [
        "Circuit breaker configuration (error threshold, window size, half-open probe count)",
        "Retry policy configuration (max retries, backoff base, jitter)",
        "Feature flag or config toggle for emergency KYC bypass"
      ],
      "infra_provisioning": []
    },
    "database_safety": {
      "has_migrations": false,
      "reversible": false,
      "data_preserving": false,
      "large_table_impact": false,
      "details": "No database migrations mentioned. If a 'pending verification' user state is added for degraded mode, a schema change would be needed to track KYC status asynchronously."
    },
    "verdict": "NOT READY"
  },

  "escalations": [
    {
      "type": "integration_risk",
      "issue": "Onfido dependency makes internal SLA mathematically unachievable",
      "reason": "The team targets 99.95% uptime but depends synchronously on Onfido at 99.9% with no fallback. This guarantees SLA violation. The blast radius is total: 100% of new user registrations fail when Onfido is unavailable. A degraded-mode architecture decision (async KYC, secondary provider, or emergency bypass) is required before this can ship, and that decision has architectural implications that need MJ's input.",
      "routed_to": "MJ"
    },
    {
      "type": "integration_risk",
      "issue": "No circuit breaker on critical external dependency",
      "reason": "Without a circuit breaker, Onfido degradation (slow responses, partial errors) will exhaust connection pools and server threads, potentially cascading failures beyond just the KYC path to the entire registration service. The blast radius extends to any other endpoints served by the same process. Need MJ to confirm whether the KYC service is isolated or shares infrastructure with other registration components.",
      "routed_to": "MJ"
    }
  ],

  "confidence": {
    "level": 60,
    "high_confidence_areas": [
      "SLA arithmetic: 99.9% dependency cannot support 99.95% target without fallback — this is a hard mathematical fact",
      "Circuit breaker gap is a well-understood anti-pattern for synchronous external calls",
      "Timeout configuration (5s vs 3s p99) is reasonable"
    ],
    "low_confidence_areas": [
      "Whether other registration endpoints share the same process and would be affected by thread/connection exhaustion",
      "Whether there is an existing user state model that could support a 'pending verification' state without schema changes",
      "Traffic volume and registration rate — determines severity of thundering herd risk",
      "Whether Onfido provides webhook-based async verification as an alternative to polling"
    ],
    "assumptions": [
      "No other KYC fallback provider is available or integrated",
      "The service is stateless and the rollback strategy (redeploy previous image) is valid",
      "The 99.95% SLA target applies to the registration flow specifically, not just the KYC microservice in isolation",
      "Onfido's 99.9% SLA is their contractual commitment, not observed uptime — actual availability may differ"
    ]
  }
}

